import{_ as e,c as i,o as s,ae as t}from"./chunks/framework.B7Y1jjX-.js";const m=JSON.parse('{"title":"6.1 图的基本概念","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/学习/408/数据结构/第六章 图.md","filePath":"generated-notes/学习/408/数据结构/第六章 图.md"}'),n={name:"generated-notes/学习/408/数据结构/第六章 图.md"};function r(d,a,p,h,l,o){return s(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="_6-1-图的基本概念" tabindex="-1">6.1 图的基本概念 <a class="header-anchor" href="#_6-1-图的基本概念" aria-label="Permalink to &quot;6.1 图的基本概念&quot;">​</a></h1><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029180546.png">查看图片：Pasted image 20251029180546.png</a> 主要掌握==深度优先==搜索与==广度优先==搜索。掌握图的基本概念及基本性质、图的存储结构（邻接矩阵、邻接表、邻接多重表和十字链表）及其特性、存储结构之间的转化。基于存储结构上的遍历操作和各种应用（拓扑排序、最小生成树、最短路径和关键路径）等。图的相关算法较多通常只要求掌握其基本思想和实现步骤，而算法的具体实现不是重点。</p><h2 id="_6-1-1-图的定义" tabindex="-1">6.1.1 图的定义 <a class="header-anchor" href="#_6-1-1-图的定义" aria-label="Permalink to &quot;6.1.1 图的定义&quot;">​</a></h2><p>图G由顶点集V和边集E组成，记为G=(V,E) 其中V(G)表示图G中顶点的==有限非空集==；E(G)表示图G中顶点之间的关系（边）集合。</p><p>线性表可以是空表，树可以是空树，但图==不可以是空图==。图的顶点集V一定非空，但边集召可以为空，此时只有顶点而没有边。</p><h3 id="稠密图与稀疏图" tabindex="-1">稠密图与稀疏图 <a class="header-anchor" href="#稠密图与稀疏图" aria-label="Permalink to &quot;稠密图与稀疏图&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029182133.png">查看图片：Pasted image 20251029182133.png</a></p><h3 id="有向图" tabindex="-1">有向图 <a class="header-anchor" href="#有向图" aria-label="Permalink to &quot;有向图&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029180418.png">查看图片：Pasted image 20251029180418.png</a></p><h3 id="无向图" tabindex="-1">无向图 <a class="header-anchor" href="#无向图" aria-label="Permalink to &quot;无向图&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029180437.png">查看图片：Pasted image 20251029180437.png</a></p><h3 id="简单图、多重图" tabindex="-1">简单图、多重图 <a class="header-anchor" href="#简单图、多重图" aria-label="Permalink to &quot;简单图、多重图&quot;">​</a></h3><p>不存在重复的边与和自己连接的环。一般数据结构中仅仅讨论简单图。</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029180746.png">查看图片：Pasted image 20251029180746.png</a></p><h3 id="完全图-简单完全图" tabindex="-1">完全图（简单完全图） <a class="header-anchor" href="#完全图-简单完全图" aria-label="Permalink to &quot;完全图（简单完全图）&quot;">​</a></h3><p>各个点之间都有边</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029180928.png">查看图片：Pasted image 20251029180928.png</a></p><h3 id="子图、生成子图" tabindex="-1">子图、生成子图 <a class="header-anchor" href="#子图、生成子图" aria-label="Permalink to &quot;子图、生成子图&quot;">​</a></h3><p>G的一部分边与点构成的图。并非V和E的任何子集都能构成G的子图，因为这样的子集可能不是图。 若==V(G)=V(G&#39;)==，子图G‘是G的生成子图</p><h3 id="路径、路径长度与回路" tabindex="-1">路径、路径长度与回路 <a class="header-anchor" href="#路径、路径长度与回路" aria-label="Permalink to &quot;路径、路径长度与回路&quot;">​</a></h3><p>路径指包括首尾的由边连着的链状的==点集==。 路径长度是==边的个数==。 回路指==首尾相连==。</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029181611.png">查看图片：Pasted image 20251029181611.png</a></p><h3 id="简单路径与简单回路" tabindex="-1">简单路径与简单回路 <a class="header-anchor" href="#简单路径与简单回路" aria-label="Permalink to &quot;简单路径与简单回路&quot;">​</a></h3><p>==没有重复==的顶点，当然不包括首尾。</p><h3 id="距离" tabindex="-1">距离 <a class="header-anchor" href="#距离" aria-label="Permalink to &quot;距离&quot;">​</a></h3><p>==最短的路径长度==。</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029182021.png">查看图片：Pasted image 20251029182021.png</a></p><h3 id="网与权" tabindex="-1">网与权 <a class="header-anchor" href="#网与权" aria-label="Permalink to &quot;网与权&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029182239.png">查看图片：Pasted image 20251029182239.png</a> 带权路径长度：一条路径所有边的权的和。</p><h3 id="连通、连通图与连通分量-针对无向图" tabindex="-1">连通、连通图与连通分量（针对无向图） <a class="header-anchor" href="#连通、连通图与连通分量-针对无向图" aria-label="Permalink to &quot;连通、连通图与连通分量（针对无向图）&quot;">​</a></h3><p>对于n个顶点的G图： 是连通图，至少有n-1条边 非连通图，最多有以n-2为底的C^2 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029181508.png">查看图片：Pasted image 20251029181508.png</a></p><h3 id="强连通图与强连通分量-针对有向图" tabindex="-1">强连通图与强连通分量（针对有向图） <a class="header-anchor" href="#强连通图与强连通分量-针对有向图" aria-label="Permalink to &quot;强连通图与强连通分量（针对有向图）&quot;">​</a></h3><p>有向图强连通情况下边最少的情况：至少需要n条边，构成一个环路。</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029182626.png">查看图片：Pasted image 20251029182626.png</a></p><h3 id="有向树" tabindex="-1">有向树 <a class="header-anchor" href="#有向树" aria-label="Permalink to &quot;有向树&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029182412.png">查看图片：Pasted image 20251029182412.png</a></p><h3 id="顶点的度、入度与出度" tabindex="-1">顶点的度、入度与出度 <a class="header-anchor" href="#顶点的度、入度与出度" aria-label="Permalink to &quot;顶点的度、入度与出度&quot;">​</a></h3><p>无向图：所有点度的和 = 2 * 边的数量 有向图：入度和 = 出度和 = 边的数量</p><h1 id="_6-2-图的存储形式与基本操作" tabindex="-1">6.2 图的存储形式与基本操作 <a class="header-anchor" href="#_6-2-图的存储形式与基本操作" aria-label="Permalink to &quot;6.2 图的存储形式与基本操作&quot;">​</a></h1><h2 id="_6-2-1-邻接矩阵" tabindex="-1">6.2.1 邻接矩阵 <a class="header-anchor" href="#_6-2-1-邻接矩阵" aria-label="Permalink to &quot;6.2.1 邻接矩阵&quot;">​</a></h2><p>将邻接的关系保存在二维数组中。</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029214015.png">查看图片：Pasted image 20251029214015.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029214029.png">查看图片：Pasted image 20251029214029.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029214112.png">查看图片：Pasted image 20251029214112.png</a></p><h3 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to &quot;特点&quot;">​</a></h3><ul><li>无向图的邻接矩阵是==对称矩阵==，对规模特大的邻接矩阵可采用==压缩存储==。</li><li>邻接矩阵表示法的空间复杂度为 O(|V|)</li><li>对于无向图，邻接矩阵的第i行(或第i列)非零元素(或非∞元素)的个数正好是顶点 i 的度 TD(v)。</li><li><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029214421.png">查看图片：Pasted image 20251029214421.png</a></li><li>用邻接矩阵存储图，很容易确定图中两个顶点之间是否有边相连。但是，要确定图中有多少条边、则必须按行、按列对每个元素进行检测，花费的时间代价很大。</li><li>==稠密图==适合使用邻接矩阵的存储表示。</li><li><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029214507.png">查看图片：Pasted image 20251029214507.png</a></li></ul><h2 id="_6-2-2-邻接表" tabindex="-1">6.2.2 邻接表 <a class="header-anchor" href="#_6-2-2-邻接表" aria-label="Permalink to &quot;6.2.2 邻接表&quot;">​</a></h2><p>一个图为稀疏图时，使用邻接矩阵法要浪费大量空间。图的邻接表法结合了顺序存储和链式存储方法，大大减少浪费。</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029222900.png">查看图片：Pasted image 20251029222900.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029222955.png">查看图片：Pasted image 20251029222955.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029223409.png">查看图片：Pasted image 20251029223409.png</a></p><p>特点：</p><ul><li>若 G为无向图，则所需的存储空间为 O(|V|+2|E|)，2是由于无向图中，每条边在邻接表中出现了两次。</li><li>若 G为有向图，则所需的存储空间为O(|V|+|E|)</li><li>对于稀疏图，采用邻接表表示将极大地节省存储空间。</li><li>在邻接表中，能很容易地找出一个顶点的所有邻边。在邻接矩阵中，相同的操作则需要扫描一行，花费的时间为 0(n)。</li><li>若要确定给定的两个顶点间是否存在边，则在邻接矩阵中可以立刻查到，而在邻接表中则需要在相应结点对应的边表中查找另一结点，效率较低。</li><li>图的邻接表表示并不唯一，它取决于建立邻接表的算法及边的输入次序。而邻接矩阵是唯一的。</li><li>在有向图的邻接表表示中，求一个给定顶点的出度只需计算其邻接表中的结点个数;但求其顶点的入度则需要遍历全部的邻接表。</li></ul><h2 id="_6-2-3-十字链表-有向图" tabindex="-1">6.2.3 十字链表（有向图） <a class="header-anchor" href="#_6-2-3-十字链表-有向图" aria-label="Permalink to &quot;6.2.3 十字链表（有向图）&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029223854.png">查看图片：Pasted image 20251029223854.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029223917.png">查看图片：Pasted image 20251029223917.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029224006.png">查看图片：Pasted image 20251029224006.png</a> 图的十字链表表示是不唯一的，但一个十字链表表示确定一个图。 空间复杂度：O(|V|+|E|)</p><h2 id="_6-2-4-邻接多重表-无向图" tabindex="-1">6.2.4 邻接多重表（无向图） <a class="header-anchor" href="#_6-2-4-邻接多重表-无向图" aria-label="Permalink to &quot;6.2.4 邻接多重表（无向图）&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029224140.png">查看图片：Pasted image 20251029224140.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029224322.png">查看图片：Pasted image 20251029224322.png</a> 空间复杂度：O(|V|+|E|)</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029224622.png">查看图片：Pasted image 20251029224622.png</a> 理解，邻接多重表与十字链表，其代码实现较复杂，不会考察代码。</p><h2 id="_6-2-5-图的基本操作" tabindex="-1">6.2.5 图的基本操作 <a class="header-anchor" href="#_6-2-5-图的基本操作" aria-label="Permalink to &quot;6.2.5 图的基本操作&quot;">​</a></h2><ul><li>Adjacent(G,x,y):判断图G是否存在边&lt;x,y&gt;或(x,y)。 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029224831.png">查看图片：Pasted image 20251029224831.png</a></li></ul><h1 id="_6-3-图的遍历" tabindex="-1">6.3 图的遍历 <a class="header-anchor" href="#_6-3-图的遍历" aria-label="Permalink to &quot;6.3 图的遍历&quot;">​</a></h1><h2 id="_6-3-1-广度优先搜索bfs" tabindex="-1">6.3.1 广度优先搜索BFS <a class="header-anchor" href="#_6-3-1-广度优先搜索bfs" aria-label="Permalink to &quot;6.3.1 广度优先搜索BFS&quot;">​</a></h2><p>遍历图的过程是以v为起始点，由近至远依次访问和，有路径相通且路径长度为1,2,…的顶点。算法必须借助一个辅助队列，以记忆正在访问的顶点的下一层项点。、</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029231005.png">查看图片：Pasted image 20251029231005.png</a></p><h3 id="性能分析" tabindex="-1">性能分析 <a class="header-anchor" href="#性能分析" aria-label="Permalink to &quot;性能分析&quot;">​</a></h3><ul><li>无论是邻接表还是邻接矩阵的存储方式，BFS 算法都需要借助一个辅助队列，在最坏的情况下，空间复杂度为 O(|V|)。</li><li>邻接表，每个顶点均需搜索一次(或入队一次)，故时间复杂度为 O(|V|)，在搜索任意一个顶点的邻接点时，每条边至少访问一次，故时间复杂度为 O(E)，算法总的时间复杂度为 O(|V|+|E|)。</li><li>邻接矩阵，査找每个顶点的邻接点所需的时间为 O(|V|)，故算法总的时间复杂度为 O(IV|^2)。</li></ul><h3 id="广度优先生成树与森林" tabindex="-1">广度优先生成树与森林 <a class="header-anchor" href="#广度优先生成树与森林" aria-label="Permalink to &quot;广度优先生成树与森林&quot;">​</a></h3><p>广度遍历得到一棵遍历树，称为广度优先生成树：</p><ul><li>邻接矩阵存储表示是唯一的，其广度优先生成树也是唯一的，</li><li>邻接表存储表示不唯一，广度优先生成树是不唯一的。 广度优先生成树组成的森林就是广度优先生成森林 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251029231426.png">查看图片：Pasted image 20251029231426.png</a></li></ul><h2 id="_6-3-2-深度优先搜索dfs" tabindex="-1">6.3.2 深度优先搜索DFS <a class="header-anchor" href="#_6-3-2-深度优先搜索dfs" aria-label="Permalink to &quot;6.3.2 深度优先搜索DFS&quot;">​</a></h2><p>优先探索结点的孩子，直到叶子结点。之后再回溯，继续探索没有探索的孩子结点。</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030133939.png">查看图片：Pasted image 20251030133939.png</a></p><h3 id="性能分析-1" tabindex="-1">性能分析 <a class="header-anchor" href="#性能分析-1" aria-label="Permalink to &quot;性能分析&quot;">​</a></h3><ul><li>DFS 算法都需要借助栈，在最坏的情况下，空间复杂度为 O(|V|)，最好O(1)</li><li>邻接表时间复杂度O(|V|+|E|)</li><li>邻接矩阵时间复杂度O(IV|^2)</li></ul><h3 id="深度优先生成树与森林" tabindex="-1">深度优先生成树与森林 <a class="header-anchor" href="#深度优先生成树与森林" aria-label="Permalink to &quot;深度优先生成树与森林&quot;">​</a></h3><p>同一个图的邻接矩阵表示方式唯一，深度优先遍历序列唯一，树也唯一 同一个图邻接表表示方式不唯一，深度优先遍历序列不唯一，树不唯一</p><h3 id="图的遍历与连通性" tabindex="-1">图的遍历与连通性 <a class="header-anchor" href="#图的遍历与连通性" aria-label="Permalink to &quot;图的遍历与连通性&quot;">​</a></h3><p>无向图：DFS、BFS调用与连通分量数相同的次数 有向图：若起始点到其他的所有顶点都有路径，那么只调用一次。其余情况要具体分析。</p><h1 id="_6-4-图的应用" tabindex="-1">6.4 图的应用 <a class="header-anchor" href="#_6-4-图的应用" aria-label="Permalink to &quot;6.4 图的应用&quot;">​</a></h1><p>一般而言，这部分内容直接以算法设计题形式考查的可能性很小，而更多的是结合的实例来考查算法的具体手动操作过程。</p><h2 id="_6-4-1-最小生成树" tabindex="-1">6.4.1 最小生成树 <a class="header-anchor" href="#_6-4-1-最小生成树" aria-label="Permalink to &quot;6.4.1 最小生成树&quot;">​</a></h2><p>各边权值之和最小的生成树</p><h3 id="生成树" tabindex="-1">生成树 <a class="header-anchor" href="#生成树" aria-label="Permalink to &quot;生成树&quot;">​</a></h3><p>一个连通图的生成树包含图的所有顶点，并且只含尽可能少的边。对于生成树来说，若砍去它的一条边，则会使生成树变成非连通图;若给它增加一条边，则会形成图中的一条回路。</p><h3 id="性质" tabindex="-1">性质 <a class="header-anchor" href="#性质" aria-label="Permalink to &quot;性质&quot;">​</a></h3><ul><li>最小生成树并不是唯一的。只有在图的各边的权值互不相同的时候才是唯一的。</li><li>G本身是一棵树时，则G的最小生成树就是它本身。</li><li>最小生成树的边数为顶点数减1。</li><li>最小生成树的边的权值之和总是唯一的，而且是最小的，虽然树本身并不唯一。</li><li>假设 G=(V,E)是一个带权连通无向图，U是顶点集V的一个非空子集。若(u,v)是一条具有最小权值的边，其中u属于U，v属于V-U，则必存在一棵包含边(u,v)的最小生成树。</li></ul><h3 id="prim算法" tabindex="-1">Prim算法 <a class="header-anchor" href="#prim算法" aria-label="Permalink to &quot;Prim算法&quot;">​</a></h3><p>从开始的点，选择一条权值最小的边，加入U中。再在U中所有点的边中选择一条权值最小的边。重复，直到全部加入U中。</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030163841.png">查看图片：Pasted image 20251030163841.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030163851.png">查看图片：Pasted image 20251030163851.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030164115.png">查看图片：Pasted image 20251030164115.png</a> 时间复杂度：O(|V^2|)。适合用于求解边稠密的图。</p><h3 id="kruskal算法" tabindex="-1">Kruskal算法 <a class="header-anchor" href="#kruskal算法" aria-label="Permalink to &quot;Kruskal算法&quot;">​</a></h3><p>最开始将所有的点视为一个连通分量，在这些连通分量中寻找权值最短的边，被边连上的点，算为一个新的连通分量。重复，直到只剩一个连通分量。</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030164539.png">查看图片：Pasted image 20251030164539.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030164608.png">查看图片：Pasted image 20251030164608.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030164618.png">查看图片：Pasted image 20251030164618.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030164629.png">查看图片：Pasted image 20251030164629.png</a> 时间复杂度：O(|E|log2|E|)。适合于边稀疏而顶点较多的图。</p><h2 id="_6-4-2-最短路径" tabindex="-1">6.4.2 最短路径 <a class="header-anchor" href="#_6-4-2-最短路径" aria-label="Permalink to &quot;6.4.2 最短路径&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030165653.png">查看图片：Pasted image 20251030165653.png</a> 最短路径：权值最少的路径</p><ul><li>单源最短路径：从一个结点出发。 <ul><li>BFS</li><li>Dijkstra</li></ul></li><li>每对顶点间的最短路径：将所有的结点之间的最短路径都求出来。 <ul><li>Floyd</li></ul></li></ul><h3 id="bfs求无权图的单源最短路径" tabindex="-1">BFS求无权图的单源最短路径 <a class="header-anchor" href="#bfs求无权图的单源最短路径" aria-label="Permalink to &quot;BFS求无权图的单源最短路径&quot;">​</a></h3><p>将无权图视为权位1，实现的过程与BFS遍历很像。要添加辅助数组，记录距离与前驱 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030165024.png">查看图片：Pasted image 20251030165024.png</a></p><h3 id="dijkstra算法求单源最短路径-贪心" tabindex="-1">Dijkstra算法求单源最短路径（贪心） <a class="header-anchor" href="#dijkstra算法求单源最短路径-贪心" aria-label="Permalink to &quot;Dijkstra算法求单源最短路径（贪心）&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030165938.png">查看图片：Pasted image 20251030165938.png</a> 每轮选择距离最短的顶点固定，将这个点连接的所有边加上到他自己的距离的和如果小于对应顶点的距离，就更新。重复，直到将所有的点固定。固定的点不再参与比较。 在这个图中，顶点5在第一轮距离为5，值最小，就固定，它与2、4相连，2+5=7，3+5=8&lt;10。都符合更新的条件。 边上带有负权值时，Dijkstra 算法并不适用。</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030170517.png">查看图片：Pasted image 20251030170517.png</a></p><h3 id="floyd算法求每对顶点间的最短路径-dp" tabindex="-1">Floyd算法求每对顶点间的最短路径（DP） <a class="header-anchor" href="#floyd算法求每对顶点间的最短路径-dp" aria-label="Permalink to &quot;Floyd算法求每对顶点间的最短路径（DP）&quot;">​</a></h3><p>考试只会考阶数较少的，如3阶：</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030171648.png">查看图片：Pasted image 20251030171648.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030172201.png">查看图片：Pasted image 20251030172201.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030172312.png">查看图片：Pasted image 20251030172312.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030172558.png">查看图片：Pasted image 20251030172558.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030172749.png">查看图片：Pasted image 20251030172749.png</a> 时间复杂度，O(|V^3|) 空间复杂度，O(IV^2|)</p><h2 id="_6-4-3-有向无环图表达式" tabindex="-1">6.4.3 有向无环图表达式 <a class="header-anchor" href="#_6-4-3-有向无环图表达式" aria-label="Permalink to &quot;6.4.3 有向无环图表达式&quot;">​</a></h2><p>若一个有向图中不存在环，则称为有向无环图，简称 DAG 图。 有向无环图是描述含有公共子式的表达式的有效工具。例如表达式 ( (a+b) * (b * (c+d))+(c+d) * e) * ((c+d) * e )</p><p>利用有向无环图，则可实现对相同子式的共享，从而节省存储空间 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030173239.png">查看图片：Pasted image 20251030173239.png</a> 表达式中的字母会作为树的==叶子结点==，同时==不会重复==。</p><h2 id="_6-4-4-拓扑排序" tabindex="-1">6.4.4 拓扑排序 <a class="header-anchor" href="#_6-4-4-拓扑排序" aria-label="Permalink to &quot;6.4.4 拓扑排序&quot;">​</a></h2><p>使用有向无环图来表示具有“前后顺序”的活动</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030173434.png">查看图片：Pasted image 20251030173434.png</a></p><p>时间复杂度：O(|V|+|E|)，若采用邻接矩阵则需O(|V|^2)</p><h3 id="算法实现" tabindex="-1">算法实现 <a class="header-anchor" href="#算法实现" aria-label="Permalink to &quot;算法实现&quot;">​</a></h3><ul><li>从 AOV 网中选择一个没有前驱的顶点并输出。</li><li>从网中删除该顶点和所有以它为起点的有向边。</li><li>重复，直到没有点。</li></ul><h3 id="逆拓扑排序" tabindex="-1">逆拓扑排序 <a class="header-anchor" href="#逆拓扑排序" aria-label="Permalink to &quot;逆拓扑排序&quot;">​</a></h3><p>逆着图来做</p><h2 id="_6-4-5-关键路径" tabindex="-1">6.4.5 关键路径 <a class="header-anchor" href="#_6-4-5-关键路径" aria-label="Permalink to &quot;6.4.5 关键路径&quot;">​</a></h2><p>在AOE网中，具有最大路径长度的路径称为关键路径，而把关键路径上的活动称为关键活动，就是整个工程想要完成的最短时间。特性：</p><ul><li>关键活动耗时增加，整个工程时间增加。</li><li>关键活动耗时减少，整个工程时间减少。</li><li>关键活动耗时减少到一定程度，可能会变为非关键活动。</li><li>可能具有多条关键路径（耗时相同）。</li></ul><h3 id="aoe网" tabindex="-1">AOE网 <a class="header-anchor" href="#aoe网" aria-label="Permalink to &quot;AOE网&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030175024.png">查看图片：Pasted image 20251030175024.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030175006.png">查看图片：Pasted image 20251030175006.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030174945.png">查看图片：Pasted image 20251030174945.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030174815.png">查看图片：Pasted image 20251030174815.png</a></p><p>可以将顶点理解为一瞬间完成，而边需要一段时间。</p><h3 id="相关定义" tabindex="-1">相关定义 <a class="header-anchor" href="#相关定义" aria-label="Permalink to &quot;相关定义&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030175613.png">查看图片：Pasted image 20251030175613.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030175626.png">查看图片：Pasted image 20251030175626.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030180016.png">查看图片：Pasted image 20251030180016.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030180025.png">查看图片：Pasted image 20251030180025.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030180110.png">查看图片：Pasted image 20251030180110.png</a> 若果一个活动的时间余量为0，那么它就是关键活动，由关键活动组成的路径，就是关键路径。</p><h3 id="算法" tabindex="-1">算法 <a class="header-anchor" href="#算法" aria-label="Permalink to &quot;算法&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030180630.png">查看图片：Pasted image 20251030180630.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030181006.png">查看图片：Pasted image 20251030181006.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030181115.png">查看图片：Pasted image 20251030181115.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030181257.png">查看图片：Pasted image 20251030181257.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251030181325.png">查看图片：Pasted image 20251030181325.png</a></p>',125)])])}const P=e(n,[["render",r]]);export{m as __pageData,P as default};
